#include <bits/stdc++.h>
using namespace std;

int main(){
string s, s1, s2;
int n;
s1 = "001";
s2 = "00";
s = "1";
for (int i = 0; i < 80; i++){
s += "0";
}
while (s.find("10") != std::string::npos || s.find("1") != std::string::npos){
if (s.find("10") != std::string::npos)
s = s.replace(s.find("10"), 2, s1);
else if (s.find("1") != std::string::npos)
s = s.replace(s.find("1"), 5, s2);
}
